def max_depth(tree):
    """
    Calculates the maximum depth of a binary tree.

    Args:
        tree: A list representing the binary tree.  We assume that 'nh' or 'n*p' or 'n8p' or None represent null nodes.

    Returns:
        The maximum depth of the tree.
    """

    if not tree or tree[0] in ('nh', 'n*p', 'n8p', None):
        return 0

    def depth(node, index):
        if index >= len(tree) or tree[index] in ('nh', 'n*p', 'n8p', None):
            return 0

        return 1 + max(depth(tree, 2*index + 1), depth(tree, 2*index + 2))

    return depth(tree, 0)

def max_depth(tree):
    """
    Calculates the maximum depth of a binary tree.

    Args:
        tree: A list representing the binary tree.  Non-numeric values
              represent null nodes.

    Returns:
        The maximum depth of the tree.
    """

    if not tree or len(tree) == 0 or (len(tree) == 1 and not isinstance(tree[0], (int, float))):
        return 0

    def is_valid_node(node):
        return isinstance(node, (int, float))

    def calculate_depth(node_index, current_depth):
        if node_index >= len(tree) or not is_valid_node(tree[node_index]):
            return current_depth

        left_child_index = 2 * node_index + 1
        right_child_index = 2 * node_index + 2

        left_depth = calculate_depth(left_child_index, current_depth + 1)
        right_depth = calculate_depth(right_child_index, current_depth + 1)

        return max(left_depth, right_depth)

    return calculate_depth(0, 1)

